mapper.select:
SELECT 'SUBMITTED' AS row_type, c.id AS customer_id, l.id AS lead_id, c.phone AS phone, l.surname AS surname, l.region AS region, l.debt_amount AS debt_amount, l.debt_type AS debt_type, l.debt_description AS debt_description, l.age_range AS age_range, l.job_status AS job_status, l.credit_status AS credit_status, l.monthly_income_range AS monthly_income_range, l.monthly_expense_range AS monthly_expense_range, l.source AS source, c.first_login_at AS first_login_at, l.created_at AS lead_created_at, CASE WHEN qr.last_wechat_qr_view_at IS NULL THEN 0 ELSE 1 END AS viewed_wechat_qr, qr.last_wechat_qr_view_at AS last_wechat_qr_view_at, ev.event_type AS latest_event_type, ev.created_at AS latest_event_at, history.history_count AS history_count FROM lead_record l INNER JOIN customer c ON c.id = l.customer_id
LEFT JOIN ( SELECT customer_id, COUNT(*) AS history_count FROM lead_record GROUP BY customer_id ) history ON history.customer_id = c.id WHERE c.status = 'ACTIVE'
AND (c.phone LIKE CONCAT('%', #{query.keyword}, '%') OR l.surname LIKE CONCAT('%', #{query.keyword}, '%'))
AND l.region = #{query.region}
AND l.debt_type = #{query.debtType}
AND l.debt_amount >= #{query.minDebtAmount}
AND l.debt_amount <= #{query.maxDebtAmount}
AND qr.last_wechat_qr_view_at IS NOT NULL
AND qr.last_wechat_qr_view_at IS NULL
AND l.created_at >= #{query.startTime}
AND l.created_at <= #{query.endTime}
